# Networks that share a bespoke glyph with another (or reuse a generic-ish one).
_SVG["twitter"] = _SVG["x"]

# ── the catalog ────────────────────────────────────────────────────────────────
# share_url templates use {url}, {title}, {image} placeholders (see brand_social_links).
_CATALOG_RAW = [
    # key,        label,         icon,          share_url_template,                                                            payment
    ("facebook",  "Facebook",    "facebook",    "https://www.facebook.com/sharer/sharer.php?u={url}",                          False),
    ("x",         "X",           "x",           "https://twitter.com/share?url={url}&text={title}",                            False),
    ("linkedin",  "LinkedIn",    "linkedin",    "https://www.linkedin.com/shareArticle?mini=true&url={url}&title={title}",     False),
    ("whatsapp",  "WhatsApp",    "whatsapp",    "https://api.whatsapp.com/send?text={title}%20{url}",                          False),
    ("pinterest", "Pinterest",   "pinterest",   "https://pinterest.com/pin/create/button/?url={url}&media={image}&description={title}", False),
    ("reddit",    "Reddit",      "reddit",      "https://www.reddit.com/submit?url={url}&title={title}",                       False),
    ("telegram",  "Telegram",    "telegram",    "https://t.me/share/url?url={url}&text={title}",                               False),
    ("threads",   "Threads",     "threads",     "https://www.threads.net/intent/post?text={title}%20{url}",                    False),
    ("bluesky",   "Bluesky",     "bluesky",     "https://bsky.app/intent/compose?text={title}%20{url}",                        False),
    ("tumblr",    "Tumblr",      "tumblr",      "https://www.tumblr.com/share/link?url={url}&name={title}",                    False),
    ("email",     "Email",       "email",       "mailto:?subject={title}&body={url}",                                          False),
    # ── display-only (share_url = None → never rendered in a sharing section, D1) ──
    ("youtube",   "YouTube",     "youtube",     None, False),
    ("tiktok",    "TikTok",      "tiktok",      None, False),
    ("instagram", "Instagram",   "instagram",   None, False),
    ("github",    "GitHub",      "github",      None, False),
    ("vimeo",     "Vimeo",       "vimeo",       None, False),
    ("soundcloud","SoundCloud",  "soundcloud",  None, False),
    ("spotify",   "Spotify",     "spotify",     None, False),
    ("buzzfeed",  "BuzzFeed",    "buzzfeed",    None, False),
    ("substack",  "Substack",    "substack",    None, False),
    ("slack",     "Slack",       "slack",       None, False),
    ("snapchat",  "Snapchat",    "snapchat",    None, False),
    ("discord",   "Discord",     "discord",     None, False),
    ("twitch",    "Twitch",      "twitch",      None, False),
    ("medium",    "Medium",      "medium",      None, False),
    ("website",   "Website",     "website",     None, False),
    # ── payment platforms (D4: same list, display-only) ──
    ("paypal",    "PayPal",      "paypal",      None, True),
    ("stripe",    "Stripe",      "stripe",      None, True),
    ("venmo",     "Venmo",       "venmo",       None, True),
    ("cashme",    "CashMe",      "cashme",      None, True),   # D7: label is "CashMe"
    ("patreon",   "Patreon",     "patreon",     None, True),
    ("shopify",   "Shopify",     "shopify",     None, True),
]

SOCIAL_CATALOG = [
    {
        "key": key,
        "label": label,
        "icon": icon,
        "share_url": share_url,
        "share_capable": share_url is not None,
        "payment": payment,
        "svg": _SVG.get(icon, GENERIC_SVG),
    }
    for (key, label, icon, share_url, payment) in _CATALOG_RAW
]

_BY_KEY = {c["key"]: c for c in SOCIAL_CATALOG}
# Legacy free-text platform / icon values → catalog key (for on-read normalization).
_ALIASES = {
    "twitter": "x", "x / twitter": "x", "twitter/x": "x",
    "cash app": "cashme", "cashapp": "cashme", "cash me": "cashme",
    "google": "website", "web": "website", "site": "website",
    "mail": "email", "e-mail": "email",
}


def get(key: str) -> dict | None:
    """Catalog entry for a key (or a known alias), else None."""
    if not key:
        return None
    k = str(key).strip().lower()
    return _BY_KEY.get(k) or _BY_KEY.get(_ALIASES.get(k, ""))


def resolve_key(platform: str = "", icon: str = "", key: str = "") -> str | None:
    """Best-effort catalog key for a (possibly legacy) social row.

    Order: explicit key → icon → platform label → alias table. Returns None when
    nothing matches (a genuine custom/free-form row — kept as-is by the caller).
    """
    for cand in (key, icon, platform):
        entry = get(cand)
        if entry:
            return entry["key"]
    return None
